// Thresholds live here so they can be tuned without touching SQL.
const THRESHOLDS = {
  tutor_complaint_rate: 0.15,
  ux_complaint_rate: 0.15,
  high_severity_tutor_rate: 0.10
};

return items.map(item => {
  const value = item.json.value ?? 0;
  const threshold = THRESHOLDS[item.json.kpi_name] ?? 1;
  const status = value > threshold ? 'breach' : (value > threshold * 0.8 ? 'warning' : 'ok');
  return {
    json: {
      snapshot_date: new Date().toISOString().slice(0, 10),
      role: item.json.role,
      kpi_name: item.json.kpi_name,
      value,
      threshold,
      status
    }
  };
});

// Mock rows shaped like "Calculate KPIs" (Postgres UNION ALL) output:
// kpi_name, role, value
// Covers a breach, an ok, and a warning-band result across the three KPIs.
return [
  { json: { kpi_name: 'tutor_complaint_rate', role: 'Course Lead', value: 0.22 } },      // breach (> 0.15)
  { json: { kpi_name: 'ux_complaint_rate', role: 'QA Lead', value: 0.05 } },              // ok (< 0.12)
  { json: { kpi_name: 'high_severity_tutor_rate', role: 'Course Lead', value: 0.085 } }   // warning (0.08 < x <= 0.10)
];
